import React, { useState, useEffect } from 'react';

const SearchBar = ({ city, setCity, onSearch }) => {
  const [suggestions, setSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  // Fetch suggestions from WeatherAPI as the user types
  useEffect(() => {
    const fetchSuggestions = async () => {
      if (city.trim().length > 2) {
        try {
          const API_KEY = "9639c7cedda74131876100024262504"; // Use your existing key
          const response = await fetch(
            `https://api.weatherapi.com/v1/search.json?key=${API_KEY}&q=${city}`
          );
          const data = await response.json();
          setSuggestions(data);
          setShowSuggestions(true);
        } catch (error) {
          console.error("Error fetching suggestions:", error);
        }
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    };

    const timeoutId = setTimeout(fetchSuggestions, 300); // Debounce to save API calls
    return () => clearTimeout(timeoutId);
  }, [city]);

  const handleSelect = (cityName) => {
    setCity(cityName);
    setShowSuggestions(false);
    onSearch(); // Trigger search immediately upon selection
  };

  return (
    <div className="search-container" style={{ position: 'relative' }}>
      <input
        type="text"
        value={city}
        onChange={(e) => setCity(e.target.value)}
        placeholder="Enter city"
        onKeyDown={(e) => e.key === "Enter" && onSearch()}
        autoComplete="off"
      />
      
      {showSuggestions && suggestions.length > 0 && (
        <ul className="suggestions-list">
          {suggestions.map((item) => (
            <li key={item.id} onClick={() => handleSelect(item.name)}>
              {item.name}, {item.region}
            </li>
          ))}
        </ul>
      )}

      <button onClick={() => city.trim() !== "" && onSearch()}>
        Search
      </button>
    </div>
  );
};

export default SearchBar;
